import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import './AdminLogin.css';

const AdminLogin = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        // Client-side validation
        if (!username.trim()) {
            setError('Please enter your username');
            return;
        }
        
        if (!password) {
            setError('Please enter your password');
            return;
        }
        
        setLoading(true);
        setError('');
        setSuccess('');
        
        const result = await login(username, password);
        
        if (result.success) {
            setSuccess(result.message || 'Login successful! Redirecting...');
            setTimeout(() => {
                navigate('/admin/panel');
            }, 1500);
        } else {
            // Display the specific error message from the server
            setError(result.error || 'Invalid username or password. Please try again.');
        }
        
        setLoading(false);
    };

    return (
        <div className="admin-login-container">
            <div className="admin-login-card">
                <div className="login-header">
                    <i className="fas fa-landmark"></i>
                    <h2>Dashen Bank</h2>
                    <p>Administrator Login</p>
                </div>
                
                {/* Success Message */}
                {success && (
                    <div className="alert-message success">
                        <i className="fas fa-check-circle"></i>
                        <span>{success}</span>
                        <button className="alert-close" onClick={() => setSuccess('')}>
                            <i className="fas fa-times"></i>
                        </button>
                    </div>
                )}
                
                {/* Error Message */}
                {error && (
                    <div className="alert-message error">
                        <i className="fas fa-exclamation-circle"></i>
                        <span>{error}</span>
                        <button className="alert-close" onClick={() => setError('')}>
                            <i className="fas fa-times"></i>
                        </button>
                    </div>
                )}
                
                <form onSubmit={handleSubmit} className="login-form">
                    <div className="form-group">
                        <label>
                            <i className="fas fa-user"></i>
                            Username
                        </label>
                        <input
                            type="text"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            placeholder="Enter your username"
                            required
                            autoComplete="username"
                            disabled={loading}
                        />
                    </div>
                    
                    <div className="form-group">
                        <label>
                            <i className="fas fa-lock"></i>
                            Password
                        </label>
                        <div className="password-input-wrapper">
                            <input
                                type={showPassword ? 'text' : 'password'}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                placeholder="Enter your password"
                                required
                                autoComplete="current-password"
                                disabled={loading}
                            />
                            <button
                                type="button"
                                className="toggle-password"
                                onClick={() => setShowPassword(!showPassword)}
                                tabIndex="-1"
                            >
                                <i className={`fas fa-eye${showPassword ? '-slash' : ''}`}></i>
                            </button>
                        </div>
                    </div>
                    
                    <button 
                        type="submit" 
                        className="login-btn"
                        disabled={loading}
                    >
                        {loading ? (
                            <>
                                <i className="fas fa-spinner fa-spin"></i>
                                Logging in...
                            </>
                        ) : (
                            <>
                                <i className="fas fa-sign-in-alt"></i>
                                Login
                            </>
                        )}
                    </button>
                </form>
                
                <div className="login-footer">
                    <small>Secure system access. All activities are logged.</small>
                </div>
            </div>
        </div>
    );
};

export default AdminLogin;
